1	import { Redirect } from 'expo-router';
2	import { useAuth } from '@/lib/auth';
3	
4	// Role-aware landing. `useAuth()` reads the role that `AuthProvider` hydrated
5	// from SecureStore at root-layout time (US-030). The dev primitives catalog
6	// (US-029) remains directly reachable at `/primitives` for mobile-mcp
7	// verification; we only gate `/` itself.
8	export default function Index() {
9	  const { role } = useAuth();
10	  if (role === 'creator') return <Redirect href="/(creator)/feed" />;
11	  if (role === 'lister') return <Redirect href="/(lister)/dashboard" />;
12	  return <Redirect href="/(auth)" />;
13	}
